export type CalendarEventColor = 'blue' | 'green' | 'red' | 'orange' | 'purple' | 'teal' | 'yellow';
/** A rest-day entry: either a plain date string or an object with an optional display name */
export type RestDayEntry = string | {
    date: string;
    name?: string;
};
export interface CalendarEvent {
    id: string;
    startDate: string;
    endDate: string;
    title: string;
    subtitle?: string;
    icon?: any;
    color?: CalendarEventColor;
    class?: string;
    readOnly?: boolean;
}
export interface EventSlot {
    event: CalendarEvent;
    startCol: number;
    endCol: number;
    lane: number;
    isStart: boolean;
    isEnd: boolean;
}
